  1→/**
  2→ * Acceptance Test Kit — Shared Infrastructure
  3→ *
  4→ * Boots an in-process Brain server with isolated SurrealDB namespace.
  5→ * All acceptance test suites (core, orchestrator, intent, coding-session, etc.)
  6→ * build on this shared setup.
  7→ */
  8→import { afterAll, beforeAll } from "bun:test";
  9→import { randomBytes, createHash } from "node:crypto";
 10→import { readFileSync } from "node:fs";
 11→import { join } from "node:path";
 12→import { RecordId, Surreal } from "surrealdb";
 13→import * as jose from "jose";
 14→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
 15→import { createBrainServer } from "../../app/src/server/runtime/start-server";
 16→import { createRuntimeDependencies } from "../../app/src/server/runtime/dependencies";
 17→import { createSseRegistry } from "../../app/src/server/streaming/sse-registry";
 18→import { createInflightTracker } from "../../app/src/server/runtime/types";
 19→import { createNonceCache } from "../../app/src/server/oauth/nonce-cache";
 20→import { createLiveSelectManager } from "../../app/src/server/reactive/live-select-manager";
 21→import { createFeedSseBridge } from "../../app/src/server/reactive/feed-sse-bridge";
 22→// Agent activator + loop dampener are created inside createBrainServer
 23→import type { ServerConfig } from "../../app/src/server/runtime/config";
 24→import type { ServerDependencies, InflightTracker } from "../../app/src/server/runtime/types";
 25→
 26→// ── Shared AI dependencies for standalone acceptance tests ──
 27→
 28→const openrouter = createOpenRouter({ apiKey: requireTestEnv("OPENROUTER_API_KEY") });
 29→
 30→export const testAI = {
 31→  openrouter,
 32→  extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
 33→  extractionModel: openrouter(requireTestEnv("EXTRACTION_MODEL")),
 34→  embeddingModel: openrouter.textEmbeddingModel(requireTestEnv("EMBEDDING_MODEL")),
 35→  embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
 36→};
 37→
 38→/** @deprecated Use `testAI` instead. */
 39→export const smokeAI = testAI;
 40→
 41→export type AcceptanceTestRuntime = {
 42→  baseUrl: string;
 43→  surreal: Surreal;
 44→  namespace: string;
 45→  database: string;
 46→  port: number;
 47→};
 48→
 49→/** @deprecated Use `AcceptanceTestRuntime` instead. */
 50→export type SmokeTestRuntime = AcceptanceTestRuntime;
 51→
 52→export type AcceptanceSuiteOptions = {
 53→  /** Direct config overrides — applied to the ServerConfig object without touching process.env. */
 54→  configOverrides?: Partial<ServerConfig>;
 55→};
 56→
 57→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 58→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 59→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 60→
 61→/**
 62→ * Split SQL into statements respecting `{...}` block nesting.
 63→ * DEFINE FUNCTION / DEFINE EVENT bodies contain semicolons that are NOT
 64→ * statement terminators. Naively splitting on `;` breaks those bodies into
 65→ * orphaned fragments that corrupt the batch query.
 66→ */
 67→function splitSqlStatements(sql: string): string[] {
 68→  const stmts: string[] = [];
 69→  let current = "";
 70→  let depth = 0;
 71→  for (let i = 0; i < sql.length; i++) {
 72→    const ch = sql[i];
 73→    if (ch === "{") depth++;
 74→    else if (ch === "}") depth--;
 75→
 76→    if (ch === ";" && depth === 0) {
 77→      const trimmed = current.trim();
 78→      if (trimmed.length > 0) stmts.push(trimmed);
 79→      current = "";
 80→    } else {
 81→      current += ch;
 82→    }
 83→  }
 84→  const trimmed = current.trim();
 85→  if (trimmed.length > 0) stmts.push(trimmed);
 86→  return stmts;
 87→}
 88→
 89→/**
 90→ * Apply the base schema to a SurrealDB instance.
 91→ *
 92→ * DEFINE ANALYZER cannot run inside a transaction in SurrealDB v3.0+.
 93→ * The SDK may treat a multi-statement .query() as an implicit transaction,
 94→ * causing the analyzer and dependent FULLTEXT indexes to fail silently.
 95→ *
 96→ * We split the schema into three phases:
 97→ * 1. DEFINE ANALYZER (must run outside any transaction)
 98→ * 2. Schema definitions (DEFINE TABLE/FIELD/INDEX) — batch is fine
 99→ * 3. Seed data (CREATE statements) — separate batch to isolate from index errors
100→ */
101→export async function applyTestSchema(surreal: Surreal): Promise<void> {
102→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
103→
104→  // Strip full-line comments before splitting — comments may contain semicolons
105→  // (e.g. "-- The edge is the source of truth; status is a derived consequence.")
106→  // which would create spurious fragments after the split.
107→  const withoutComments = schemaSql
108→    .split("\n")
109→    .filter((line) => !line.trimStart().startsWith("--"))
110→    .join("\n");
111→
112→  // Brace-aware split: only split on `;` outside `{...}` blocks.
113→  // DEFINE FUNCTION and DEFINE EVENT bodies contain semicolons that must not
114→  // be treated as statement terminators.
115→  const statements = splitSqlStatements(withoutComments);
116→
117→  // Phase 1: DEFINE ANALYZER (must be isolated)
118→  const analyzerStmts = statements.filter((s) => s.startsWith("DEFINE ANALYZER"));
119→  for (const stmt of analyzerStmts) {
120→    await surreal.query(stmt + ";");
121→  }
122→
123→  // Phase 2: Schema definitions (DEFINE TABLE/FIELD/INDEX/FUNCTION/EVENT)
124→  const schemaStmts = statements.filter(
125→    (s) => !s.startsWith("DEFINE ANALYZER") && !s.startsWith("CREATE"),
126→  );
127→  if (schemaStmts.length > 0) {
128→    await surreal.query(schemaStmts.map((s) => s + ";").join("\n"));
129→  }
130→
131→  // Phase 3: Seed data (CREATE statements) — isolated so index issues don't block seeds
132→  const seedStmts = statements.filter((s) => s.startsWith("CREATE"));
133→  if (seedStmts.length > 0) {
134→    await surreal.query(seedStmts.map((s) => s + ";").join("\n"));
135→  }
136→}
137→
138→export function setupAcceptanceSuite(
139→  suiteName: string,
140→  options?: AcceptanceSuiteOptions,
141→): () => AcceptanceTestRuntime {
142→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
143→  const namespace = `accept_${runId}`;
144→  const suiteSlug = suiteName
145→    .toLowerCase()
146→    .replace(/[^a-z0-9]+/g, "_")
147→    .replace(/^_+|_+$/g, "");
148→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
149→
150→  let runtime: AcceptanceTestRuntime | undefined;
151→  let server: ReturnType<typeof Bun.serve> | undefined;
152→  let runtimeSurreal: Surreal | undefined;
153→  let analyticsSurreal: Surreal | undefined;
154→  let inflight: InflightTracker | undefined;
155→  let setupSucceeded = false;
156→
157→  beforeAll(async () => {
158→    const surreal = new Surreal();
159→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
160→    await withTimeout(
161→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
162→      10_000,
163→      "authenticate with SurrealDB",
