339→// ---------------------------------------------------------------------------
340→// SSE Helpers
341→// ---------------------------------------------------------------------------
342→
343→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
344→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
345→  if (!response.ok || !response.body) {
346→    throw new Error(`Failed to open SSE stream (${response.status})`);
347→  }
348→
349→  const reader = response.body.getReader();
350→  const decoder = new TextDecoder();
351→  const events: T[] = [];
352→  let buffer = "";
353→
354→  const timeout = setTimeout(() => {
355→    void reader.cancel();
356→  }, timeoutMs);
357→
358→  try {
359→    while (true) {
360→      const { value, done } = await reader.read();
361→      if (done) {
362→        break;
363→      }
364→
365→      buffer += decoder.decode(value, { stream: true });
366→      const segments = buffer.split("\n\n");
367→      buffer = segments.pop() ?? "";
368→
369→      for (const segment of segments) {
370→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
371→        if (!dataLine) {
372→          continue;
373→        }
374→
375→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
376→        events.push(event);
377→
378→        if (event.type === "error") {
379→          const errorText = (event as { error?: string }).error;
380→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
381→        }
382→
383→        if (event.type === "done") {
384→          return events;
385→        }
386→      }
387→    }
388→  } finally {
389→    clearTimeout(timeout);
390→    reader.releaseLock();
391→  }
392→
393→  return events;
394→}
