428→/**
429→ * Obtain an OAuth2 JWT access token for MCP endpoints.
430→ * Requires a SurrealDB connection to skip consent screen.
431→ */
432→export async function getOAuthToken(
433→  baseUrl: string,
434→  surreal: Surreal,
435→  sessionHeaders: Record<string, string>,
436→  scopes: string = "graph:read graph:reason session:write offline_access",
437→): Promise<string> {
438→  // Trigger JWKS key generation if not yet done
439→  await fetch(`${baseUrl}/api/auth/jwks`);
440→
441→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
442→    method: "POST",
443→    headers: { "Content-Type": "application/json" },
444→    body: JSON.stringify({
445→      client_name: `test-client-${Date.now()}`,
446→      redirect_uris: ["http://127.0.0.1:9999/callback"],
447→      grant_types: ["authorization_code", "refresh_token"],
448→      response_types: ["code"],
449→      token_endpoint_auth_method: "none",
450→    }),
451→  });
452→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
453→
454→  const { client_id } = (await dcrRes.json()) as { client_id: string };
455→
456→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
457→    cid: client_id,
458→  });
459→
460→  const { verifier, challenge } = generatePkce();
461→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
462→  authUrl.searchParams.set("client_id", client_id);
463→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
464→  authUrl.searchParams.set("response_type", "code");
465→  authUrl.searchParams.set("scope", scopes);
466→  authUrl.searchParams.set("state", "test-state");
467→  authUrl.searchParams.set("code_challenge", challenge);
468→  authUrl.searchParams.set("code_challenge_method", "S256");
469→  authUrl.searchParams.set("resource", baseUrl);
470→
471→  const authRes = await fetch(authUrl.toString(), {
472→    headers: sessionHeaders,
473→    redirect: "manual",
474→  });
475→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
476→
477→  const location = authRes.headers.get("location")!;
478→  const redirectUrl = new URL(location, baseUrl);
479→  const code = redirectUrl.searchParams.get("code") ?? "";
480→  if (!code) throw new Error(`No code in redirect: ${location}`);
481→
482→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
483→    method: "POST",
484→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
485→    body: new URLSearchParams({
486→      grant_type: "authorization_code",
487→      code,
488→      redirect_uri: "http://127.0.0.1:9999/callback",
489→      client_id,
490→      code_verifier: verifier,
491→      resource: baseUrl,
492→    }),
493→  });
494→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
495→
496→  const tokens = (await tokenRes.json()) as { access_token: string };
497→  return tokens.access_token;
498→}
