685→// ---------------------------------------------------------------------------
686→// DPoP Helpers
687→// ---------------------------------------------------------------------------
688→
689→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
690→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
691→    { name: "ECDSA", namedCurve: "P-256" },
692→    true,
693→    ["sign", "verify"],
694→  );
695→
696→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
697→  const thumbprint = await computeDPoPThumbprint(publicJwk);
698→
699→  return { privateKey, publicKey, publicJwk, thumbprint };
700→}
701→
702→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
703→  const thumbprintInput = JSON.stringify({
704→    crv: publicJwk.crv,
705→    kty: publicJwk.kty,
706→    x: publicJwk.x,
707→    y: publicJwk.y,
708→  });
709→
710→  const hashBuffer = await crypto.subtle.digest(
711→    "SHA-256",
712→    new TextEncoder().encode(thumbprintInput),
713→  );
714→
715→  return base64urlBytes(new Uint8Array(hashBuffer));
716→}
717→
718→async function createDPoPProof(
719→  keyPair: DPoPKeyPair,
720→  method: string,
721→  targetUri: string,
722→): Promise<string> {
723→  const header = {
724→    typ: "dpop+jwt" as const,
725→    alg: "ES256" as const,
726→    jwk: {
727→      kty: keyPair.publicJwk.kty,
728→      crv: keyPair.publicJwk.crv,
729→      x: keyPair.publicJwk.x,
730→      y: keyPair.publicJwk.y,
731→    },
732→  };
733→
734→  const payload = {
735→    jti: crypto.randomUUID(),
736→    htm: method,
737→    htu: targetUri,
738→    iat: Math.floor(Date.now() / 1000),
739→  };
740→
741→  const importedKey = await jose.importJWK(
742→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
743→    "ES256",
744→  );
745→
746→  return await new jose.SignJWT(payload)
747→    .setProtectedHeader(header)
748→    .sign(importedKey);
749→}
750→
751→function base64urlBytes(bytes: Uint8Array): string {
752→  const binary = String.fromCharCode(...bytes);
753→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
754→}
