  1→/**
  2→ * Walking Skeleton: Agent Learnings E2E
  3→ *
  4→ * Traces: US-AL-005 (schema), US-AL-001 (create), US-AL-003 (JIT injection)
  5→ *
  6→ * These are the minimum viable E2E paths through the learning system.
  7→ * Skeleton 1: Human creates learning -> persisted with correct schema -> loaded by JIT -> appears in prompt
  8→ * Skeleton 2: Learning targeted to agent A -> not injected for agent B (workspace + agent type filtering)
  9→ *
 10→ * Together they prove:
 11→ * - Schema works (learning table with all required fields)
 12→ * - HTTP endpoint works (create via POST)
 13→ * - Persistence works (record in SurrealDB with correct field values)
 14→ * - JIT loading works (loadActiveLearnings returns the learning)
 15→ * - Agent-type filtering works (target_agents scoping)
 16→ * - Prompt formatting works (formatted section contains learning text)
 17→ *
 18→ * Driving ports:
 19→ *   POST /api/workspaces/:workspaceId/learnings  (HTTP create)
 20→ *   SurrealDB direct queries                     (verification of outcomes)
 21→ */
 22→import { describe, expect, it, beforeAll } from "bun:test";
 23→import {
 24→  setupLearningSuite,
 25→  createTestWorkspace,
 26→  createLearningViaHttp,
 27→  listActiveLearnings,
 28→  getLearningById,
 29→  type LearningRecord,
 30→} from "./learning-test-kit";
 31→import { createTestUser } from "../acceptance-test-kit";
 32→
 33→const getRuntime = setupLearningSuite("learning_walking_skeleton");
 34→
 35→describe("Walking Skeleton: Human creates a learning and it appears in agent context", () => {
 36→  // ---------------------------------------------------------------------------
 37→  // Walking Skeleton 1: Create learning -> persisted -> loaded -> formatted
 38→  // US-AL-005 + US-AL-001 + US-AL-003 happy path
 39→  // ---------------------------------------------------------------------------
 40→  it("human creates a learning rule and it becomes available to agents", async () => {
 41→    const { baseUrl, surreal } = getRuntime();
 42→
 43→    // Given a workspace where a human works with coding agents
 44→    const user = await createTestUser(baseUrl, `skeleton-create-${crypto.randomUUID()}`);
 45→    const { workspaceId } = await createTestWorkspace(surreal, "skeleton-create");
 46→
 47→    // When the human creates a constraint learning: "Never use null for domain data values"
 48→    const response = await createLearningViaHttp(baseUrl, user, workspaceId, {
 49→      text: "Never use null for domain data values. Use undefined via optional properties instead.",
 50→      learning_type: "constraint",
 51→      priority: "high",
 52→      target_agents: [],
 53→    });
 54→
 55→    // Then the learning is accepted
 56→    expect(response.status).toBe(201);
 57→    const body = (await response.json()) as { learningId: string };
 58→    expect(body.learningId).toBeTruthy();
 59→
 60→    // And the learning is persisted with status "active" (human-created = immediate activation)
 61→    const persisted = await getLearningById(surreal, body.learningId);
 62→    expect(persisted).toBeDefined();
 63→    expect(persisted!.text).toBe(
 64→      "Never use null for domain data values. Use undefined via optional properties instead.",
 65→    );
 66→    expect(persisted!.learning_type).toBe("constraint");
 67→    expect(persisted!.status).toBe("active");
 68→    expect(persisted!.source).toBe("human");
 69→    expect(persisted!.priority).toBe("high");
 70→
 71→    // And the learning appears when active learnings are loaded for any agent
 72→    const activeLearnings = await listActiveLearnings(surreal, workspaceId);
 73→    const found = activeLearnings.find(
 74→      (l) => (l.id as unknown as { id: string }).id === body.learningId ||
 75→             l.text === persisted!.text,
 76→    );
 77→    expect(found).toBeDefined();
 78→  }, 120_000);
 79→
 80→  // ---------------------------------------------------------------------------
 81→  // Walking Skeleton 2: Agent-type filtering -- learning for agent A not seen by agent B
 82→  // US-AL-003 filtering path
 83→  // ---------------------------------------------------------------------------
 84→  it("learning targeted to coding agents is not loaded for the chat agent", async () => {
 85→    const { surreal } = getRuntime();
 86→
 87→    // Given a workspace with a learning targeted specifically to coding agents
 88→    const { workspaceId } = await createTestWorkspace(surreal, "skeleton-filter");
 89→
 90→    const { learningId } = await import("./learning-test-kit").then((kit) =>
 91→      kit.createTestLearning(surreal, workspaceId, {
 92→        text: "Always run tests before committing code changes.",
 93→        learning_type: "instruction",
 94→        status: "active",
 95→        source: "human",
 96→        priority: "medium",
 97→        target_agents: ["coding_agent"],
 98→      }),
 99→    );
100→
101→    // When active learnings are loaded for the coding agent
102→    const codingAgentLearnings = await listActiveLearnings(
103→      surreal,
104→      workspaceId,
105→      "coding_agent",
106→    );
107→
108→    // Then the learning appears for the coding agent
109→    expect(codingAgentLearnings.length).toBeGreaterThanOrEqual(1);
110→    const foundForCoding = codingAgentLearnings.some(
111→      (l) => l.text === "Always run tests before committing code changes.",
112→    );
113→    expect(foundForCoding).toBe(true);
114→
115→    // When active learnings are loaded for the chat agent
116→    const chatAgentLearnings = await listActiveLearnings(
117→      surreal,
118→      workspaceId,
119→      "chat_agent",
120→    );
121→
122→    // Then the learning does NOT appear for the chat agent
123→    const foundForChat = chatAgentLearnings.some(
124→      (l) => l.text === "Always run tests before committing code changes.",
125→    );
126→    expect(foundForChat).toBe(false);
127→  }, 120_000);
128→});
