 41→/**
 42→ * Creates a workspace + identity + member_of edge directly in SurrealDB.
 43→ * Use when tests need an isolated workspace without going through HTTP signup.
 44→ */
 45→export async function createWorkspaceDirectly(
 46→  surreal: Surreal,
 47→  suffix: string,
 48→  opts?: {
 49→    workspaceName?: string;
 50→    identityName?: string;
 51→    identityType?: "human" | "agent";
 52→  },
 53→): Promise<DirectWorkspaceResult> {
 54→  const workspaceId = `ws-${crypto.randomUUID()}`;
 55→  const identityId = `id-${crypto.randomUUID()}`;
 56→  const workspaceRecord = new RecordId("workspace", workspaceId);
 57→  const identityRecord = new RecordId("identity", identityId);
 58→
 59→  await surreal.query(
 60→    `CREATE $workspace CONTENT $content;`,
 61→    {
 62→      workspace: workspaceRecord,
 63→      content: {
 64→        name: opts?.workspaceName ?? `Test Workspace ${suffix}`,
 65→        status: "active",
 66→        onboarding_complete: true,
 67→        onboarding_turn_count: 0,
 68→        onboarding_summary_pending: false,
 69→        onboarding_started_at: new Date(),
 70→        created_at: new Date(),
 71→      },
 72→    },
 73→  );
 74→
 75→  await surreal.query(
 76→    `CREATE $identity CONTENT $content;`,
 77→    {
 78→      identity: identityRecord,
 79→      content: {
 80→        name: opts?.identityName ?? `Test User ${suffix}`,
 81→        type: opts?.identityType ?? "human",
 82→        identity_status: "active",
 83→        workspace: workspaceRecord,
 84→        created_at: new Date(),
 85→      },
 86→    },
 87→  );
 88→
 89→  await surreal.query(
 90→    `RELATE $identity->member_of->$workspace SET added_at = time::now();`,
 91→    { identity: identityRecord, workspace: workspaceRecord },
 92→  );
 93→
 94→  return { workspaceId, workspaceRecord, identityId, identityRecord };
 95→}
