152→/**
153→ * Creates an intent + trace record directly in SurrealDB.
154→ * Canonical helper — all intent creation in tests should use this.
155→ */
156→export async function createIntentDirectly(
157→  surreal: Surreal,
158→  workspaceId: string,
159→  requesterId: string,
160→  opts: CreateIntentOpts,
161→): Promise<{ intentId: string; intentRecord: RecordId<"intent">; traceRecord: RecordId<"trace"> }> {
162→  const intentId = `intent-${crypto.randomUUID()}`;
163→  const intentRecord = new RecordId("intent", intentId);
164→  const workspaceRecord = new RecordId("workspace", workspaceId);
165→  const requesterRecord = new RecordId("identity", requesterId);
166→  const traceId = `trace-${intentId}`;
167→  const traceRecord = new RecordId("trace", traceId);
168→
169→  await surreal.query(`CREATE $trace CONTENT $content;`, {
170→    trace: traceRecord,
171→    content: {
172→      type: "intent_submission",
173→      actor: requesterRecord,
174→      workspace: workspaceRecord,
175→      created_at: new Date(),
176→    },
177→  });
178→
179→  const intentContent: Record<string, unknown> = {
180→    goal: opts.goal,
181→    reasoning: opts.reasoning ?? "Test intent",
182→    status: opts.status ?? "draft",
183→    priority: opts.priority ?? 50,
184→    action_spec: opts.actionSpec ?? { provider: "test", action: "test", params: {} },
185→    trace_id: traceRecord,
186→    requester: requesterRecord,
187→    workspace: workspaceRecord,
188→    created_at: new Date(),
189→  };
190→
191→  if (opts.evaluation !== undefined) intentContent.evaluation = opts.evaluation;
192→  if (opts.budgetLimit !== undefined) intentContent.budget_limit = opts.budgetLimit;
193→
194→  await surreal.query(`CREATE $intent CONTENT $content;`, {
195→    intent: intentRecord,
196→    content: intentContent,
197→  });
198→
199→  if (opts.taskId) {
200→    const taskRecord = new RecordId("task", opts.taskId);
201→    await surreal.query(
202→      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
203→      { intent: intentRecord, task: taskRecord },
204→    );
205→  }
206→
207→  return { intentId, intentRecord, traceRecord };
208→}
