347→
348→/**
349→ * Queries all observations in a workspace, optionally filtered by source agent.
350→ */
351→export async function queryWorkspaceObservations(
352→  surreal: Surreal,
353→  workspaceId: string,
354→  sourceAgent?: string,
355→): Promise<Array<{
356→  id: RecordId;
357→  text: string;
358→  severity: string;
359→  status: string;
360→  source_agent: string;
361→  observation_type?: string;
362→  workspace: RecordId<"workspace">;
363→  created_at: string;
364→  updated_at?: string;
365→}>> {
366→  const workspaceRecord = new RecordId("workspace", workspaceId);
367→
368→  type ObsRow = {
369→    id: RecordId;
370→    text: string;
371→    severity: string;
372→    status: string;
373→    source_agent: string;
374→    observation_type?: string;
375→    workspace: RecordId<"workspace">;
376→    created_at: string;
377→    updated_at?: string;
378→  };
379→
380→  if (sourceAgent) {
381→    const rows = (await surreal.query(
382→      `SELECT * FROM observation WHERE workspace = $ws AND source_agent = $agent ORDER BY created_at DESC;`,
383→      { ws: workspaceRecord, agent: sourceAgent },
384→    )) as Array<ObsRow[]>;
385→    return rows[0] ?? [];
386→  }
387→
388→  const rows = (await surreal.query(
389→    `SELECT * FROM observation WHERE workspace = $ws ORDER BY created_at DESC;`,
390→    { ws: workspaceRecord },
391→  )) as Array<ObsRow[]>;
392→  return rows[0] ?? [];
393→}
