151→// ---------------------------------------------------------------------------
152→
153→function toAccountApiResponse(record: ConnectedAccountRecord): ConnectedAccountApiResponse {
154→  return {
155→    id: record.id.id as string,
156→    provider_id: record.provider.id as string,
157→    status: record.status,
158→    has_api_key: !!record.api_key_encrypted,
159→    has_bearer_token: !!record.bearer_token_encrypted,
160→    has_basic_credentials: !!record.basic_password_encrypted,
161→    has_access_token: !!record.access_token_encrypted,
